// MARK: - App Entry Point
@main
struct MyApp: App {
    // State to hold the password reset token extracted from the Universal Link.
    // Making it Optional allows us to conditionally show the reset view.
    @State private var passwordResetToken: String?

    var body: some Scene {
        WindowGroup {
            ContentView()
                // Use onOpenURL to handle incoming URLs, including Universal Links.
                .onOpenURL { url in
                    handleUniversalLink(url)
                }
                // Present the PasswordResetView as a sheet when a token is available.
                // The item parameter requires an Identifiable type, so we'll extend String.
                .sheet(item: $passwordResetToken) { token in
                    PasswordResetView(token: token)
                }
        }
