    /// Handles incoming URLs, specifically looking for password reset Universal Links.
    /// - Parameter url: The URL opened by the app.
    private func handleUniversalLink(_ url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            print("Universal Link Handler: Invalid URL components for \(url.absoluteString)")
            return
        }

        // Define the expected host and path for your password reset Universal Link.
        // Example: https://myapp.com/reset-password?token=abc123
        let expectedHost = "myapp.com"
        let expectedPath = "/reset-password"

        // Check if the URL's host and path match your expected Universal Link pattern.
        guard components.host == expectedHost,
              components.path == expectedPath else {
            print("Universal Link Handler: URL does not match expected password reset pattern: \(url.absoluteString)")
            return
        }

        // Extract the 'token' query parameter from the URL.
        guard let tokenItem = components.queryItems?.first(where: { $0.name == "token" }),
              let tokenValue = tokenItem.value,
              !tokenValue.isEmpty else {
            print("Universal Link Handler: No 'token' parameter found or it's empty in the URL: \(url.absoluteString)")
            return
        }

        print("Universal Link Handler: Password Reset Token found: \(tokenValue)")
        // Store the token. This will trigger the .sheet to present PasswordResetView.
        self.passwordResetToken = tokenValue
