// MARK: - Password Reset View
struct PasswordResetView: View {
    let token: String // The password reset token passed from the universal link handler

    @State private var newPassword = ""
    @State private var confirmPassword = ""
    @State private var isLoading = false
    @State private var errorMessage: String?
    @State private var showSuccessAlert = false

    // Environment value to dismiss the current view (sheet in this case)
    @Environment(\.dismiss) var dismiss

    var body: some View {
        NavigationView {
            Form {
                Section("Set New Password") {
                    SecureField("New Password", text: $newPassword)
                    SecureField("Confirm Password", text: $confirmPassword)
                }

                if let errorMessage = errorMessage {
                    Text(errorMessage)
                        .foregroundColor(.red)
                }

                Button("Reset Password") {
                    resetPassword()
                }
                .disabled(isLoading || newPassword.isEmpty || newPassword != confirmPassword)
            }
            .navigationTitle("Reset Password")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") {
                        dismiss() // Dismiss the sheet
                    }
                }
            }
            .overlay {
                if isLoading {
                    ProgressView("Resetting...")
                        .padding()
                        .background(.thickMaterial)
                        .cornerRadius(10)
                }
            }
            .onAppear {
                print("PasswordResetView appeared with token: \(token)")
                // In a real app, you might immediately validate the token with your backend here
                // or load any associated user information if needed.
            }
            .alert("Password Reset Successful", isPresented: $showSuccessAlert) {
                Button("OK") {
                    dismiss() // Dismiss the sheet after success
                    // Optionally navigate to login screen or home
                }
            } message: {
                Text("Your password has been successfully reset. You can now log in with your new password.")
            }
        }
    }

    /// Simulates an API call to reset the password.
    private func resetPassword() {
        isLoading = true
        errorMessage = nil // Clear previous errors

        // Basic client-side validation (should also be done server-side)
        if newPassword.count < 8 {
            errorMessage = "Password must be at least 8 characters long."
            isLoading = false
            return
        }

        if newPassword != confirmPassword {
            errorMessage = "Passwords do not match." // Should be handled by disabled state, but good for robust check
            isLoading = false
            return
        }

        print("Attempting to reset password with token: \(token)")
        print("New password (masked): \(newPassword.prefix(1))***\(newPassword.suffix(1))") // Mask for logging

        // Simulate a network request delay
        DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
            isLoading = false

            // Simulate an API response
            if newPassword == "password123" { // Example of a weak password rule check
                errorMessage = "Password cannot be 'password123'. Please choose a stronger one."
            } else if Int.random(in: 0...9) < 2 { // Simulate a random backend error (20% chance)
                errorMessage = "Failed to reset password. Please try again later."
            } else {
                print("Password reset successful for token: \(token)")
                showSuccessAlert = true // Trigger success alert
            }
        }
    }
}

